48	const PROCESSING_FEE = 5;
49	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
50	
51	const basePremiumFor = (item: Item): number => {
52	  if (item.type === "sword") return 100;
53	  if (item.type === "amulet") return 60;
54	  return 0;
55	};
56	
57	const quotePremium = (items: Item[]): number => {
58	  const base = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
59	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
60	  return base + firstInsurance + PROCESSING_FEE;
61	};
62	
63	const runStep = (step: Step): StepResult => {
64	  if (step.op === "quote") {
65	    return { premium: quotePremium(step.items) };
66	  }
67	  return { payout: 0, remainingCap: 0 };
68	};
69	
70	export const runScenario = (scenario: Scenario): ScenarioResult => {
71	  return { results: scenario.steps.map(runStep) };
72	};
